    // markdown-it レンダリング
    document.addEventListener('DOMContentLoaded', function () {
      const el = document.querySelector('.markdown');
      if (!el) return;
      const md = window.markdownit({
        html: true,
        linkify: true,
        typographer: true,
        langPrefix: 'hljs language-',
        highlight: function (str, lang) {
          if (lang && hljs.getLanguage(lang)) {
            try { return hljs.highlight(str, { language: lang, ignoreIllegals: true }).value; } catch (e) {}
          }
          return '';
        }
      });
      md.use(window.markdownitEmoji);
      el.innerHTML = md.render(el.innerText);
      twemoji.parse(el, { base: 'https://cdn.jsdelivr.net/npm/twemoji@14/assets/' });
    });
    // テーマ切り替え
    document.addEventListener('DOMContentLoaded', function () {
      const btn = document.querySelector('.theme-switch');
      const icon = btn.querySelector('i');
      let theme = localStorage.getItem('theme') ||
        (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark');
      function applyTheme(t) {
        document.documentElement.setAttribute('data-theme', t);
        localStorage.setItem('theme', t);
        icon.className = 'fas ' + (t === 'light' ? 'fa-sun' : 'fa-moon');
      }
      applyTheme(theme);
      btn.addEventListener('click', function () {
        theme = theme === 'dark' ? 'light' : 'dark';
        applyTheme(theme);
      });
    });
    // はてなブログカード
    document.addEventListener('DOMContentLoaded', function () {
      document.querySelectorAll('.js-post-body a[href]').forEach(function (a) {
        const href = a.getAttribute('href');
        if (!href.startsWith('http')) return;
        const p = a.closest('p');
        if (!p) return;
        const iframe = document.createElement('iframe');
        iframe.className = 'hatenablogcard';
        iframe.title = href;
        iframe.src = 'https://hatenablog-parts.com/embed?url=' + encodeURIComponent(href);
        iframe.setAttribute('scrolling', 'no');
        p.parentNode.insertBefore(iframe, p.nextSibling);
      });
    });
    // 目次生成
    document.addEventListener('DOMContentLoaded', function () {
      const body = document.querySelector('.js-post-body');
      if (!body) return;
      const headings = body.querySelectorAll('h2, h3, h4');
      const toc = document.querySelector('.toc');
      if (!toc || !headings.length) return;
      const root = document.createElement('ul');
      const stack = [];
      headings.forEach(function (el, i) {
        const id = 'toc-' + i;
        if (!el.id) el.id = id;
        const level = parseInt(el.tagName[1]);
        const li = document.createElement('li');
        const a = document.createElement('a');
        a.href = '#' + id;
        a.textContent = el.textContent.trim();
        li.appendChild(a);
        while (stack.length && stack[stack.length - 1].level >= level) stack.pop();
        if (!stack.length) {
          root.appendChild(li);
        } else {
          let sub = stack[stack.length - 1].li.querySelector('ul');
          if (!sub) { sub = document.createElement('ul'); stack[stack.length - 1].li.appendChild(sub); }
          sub.appendChild(li);
        }
        stack.push({ level: level, li: li });
      });
      toc.appendChild(root);
    });
    // 目次スクロールハイライト
    document.addEventListener('DOMContentLoaded', function () {
      const toc = document.querySelector('.toc');
      if (!toc) return;
      const links = toc.querySelectorAll('a');
      let lastActive = null;
      window.addEventListener('scroll', function () {
        let currentId = null;
        document.querySelectorAll('.js-post-body h2, .js-post-body h3, .js-post-body h4').forEach(function (h) {
          if (window.scrollY >= h.getBoundingClientRect().top + window.scrollY - 225) currentId = h.id;
        });
        links.forEach(function (a) {
          a.removeAttribute('aria-current');
          if (currentId && a.getAttribute('href') === '#' + currentId) {
            a.setAttribute('aria-current', 'true');
            if (lastActive !== a) {
              lastActive = a;
              toc.scrollTo({ top: a.offsetTop - toc.clientHeight / 2, behavior: 'smooth' });
            }
          }
        });
      });
    });
