    // 検索ボックス
    document.addEventListener('DOMContentLoaded', function () {
      const searchInput = document.querySelector('header nav input[type="search"]');
      if (!searchInput) return;
      searchInput.addEventListener('focus', function () {
        searchInput.classList.add('is-open');
      });
      searchInput.addEventListener('blur', function () {
        if (!searchInput.value) {
          searchInput.classList.remove('is-open');
        }
      });
    });
    // 画像モーダル
    document.addEventListener('DOMContentLoaded', function () {
      const modal = document.querySelector('.image-modal');
      const modalImg = modal.querySelector('.modal-image');
      document.querySelectorAll('.js-post-body img').forEach(function (img) {
        img.addEventListener('click', function () {
          modalImg.src = img.src.replace(/s\d{2,4}(-c)?/, 's1600');
          modal.showModal();
        });
      });
      modal.addEventListener('click', function (e) {
        if (e.target === modal) modal.close();
      });
    });
    // サイドバー(モバイル)
    document.addEventListener('DOMContentLoaded', function () {
      const toggle = document.querySelector('.side-toggle');
      const aside = document.querySelector('aside');
      const overlay = document.querySelector('.side-overlay');
      if (!toggle || !aside || !overlay) return;
      const icon = toggle.querySelector('i');
      function open() {
        aside.classList.add('is-open');
        overlay.classList.add('is-open');
        toggle.classList.add('is-open');
        if (icon) icon.className = 'fas fa-chevron-right';
      }
      function close() {
        aside.classList.remove('is-open');
        overlay.classList.remove('is-open');
        toggle.classList.remove('is-open');
        if (icon) icon.className = 'fas fa-chevron-left';
      }
      toggle.addEventListener('click', open);
      overlay.addEventListener('click', close);
      aside.querySelectorAll('.toc a').forEach(function (a) {
        a.addEventListener('click', close);
      });
    });
